{"command":"python - <<'PY'
from pathlib import Path
import os, json, re
vault=Path(os.environ['OBSIDIAN_VAULT_PATH'])
counts={}
for sub in ['entities','comparisons','concepts','queries','raw']:
    p=vault/sub
    if p.exists():
        counts[sub]=sum(1 for _ in p.rglob('*.md'))
print(json.dumps(counts, ensure_ascii=False, indent=2))
obs=vault/'.obsidian'
print('obsidian files:', sorted([x.name for x in obs.iterdir()])[:50])
PY","timeout":120}

