{"code":"from pathlib import Path
import os, re, json
from collections import Counter, defaultdict
vault = Path(os.environ['OBSIDIAN_VAULT_PATH'])
fm = re.compile(r'^---\n(.*?)\n---\n', re.S)

counts = {}
domains = Counter()
source_types = Counter()
folder_counts = {}
for folder in ['entities','concepts','comparisons','queries']:
    files = list((vault/folder).glob('*.md'))
    folder_counts[folder] = len(files)
    for f in files:
        text = f.read_text(encoding='utf-8', errors='ignore')
        m = fm.match(text)
        meta = {}
        if m:
            for line in m.group(1).splitlines():
                if ':' in line:
                    k,v = line.split(':',1)
                    meta[k.strip()] = v.strip()
        domains[(folder, meta.get('domain','unknown'))] += 1
        source_types[(folder, meta.get('source_type','unknown'))] += 1

print('folder_counts=', folder_counts)
print('top entity domains=', Counter({k[1]:v for k,v in domains.items() if k[0]=='entities'}).most_common(10))
print('top concept domains=', Counter({k[1]:v for k,v in domains.items() if k[0]=='concepts'}).most_common(10))
print('top entity source_types=', Counter({k[1]:v for k,v in source_types.items() if k[0]=='entities'}).most_common(10))
"}

