def meta_of(text):
    m = fm.match(text)
    meta = {}
    if m:
        for line in m.group(1).splitlines():
            if ':' in line:
                k,v = line.split(':',1)
                meta[k.strip()] = v.strip()
    return meta

folder_counts = {}
entity_domains = Counter()
entity_sources = Counter()
for folder in ['entities','concepts','comparisons','queries']:
    files = list((vault/folder).glob('*.md'))
    folder_counts[folder] = len(files)
    if folder == 'entities':
        for f in files:
            meta = meta_of(f.read_text(encoding='utf-8', errors='ignore'))
            entity_domains[meta.get('domain','unknown')] += 1
            entity_sources[meta.get('source_type','unknown')] += 1
print('folder_counts', folder_counts)
print('entity_domains', entity_domains.most_common())
print('entity_sources', entity_sources.most_common())
